import React, { useState } from 'react';
import { Button, Select, DateRangeFilter, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatQty, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, monthStartEnd, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { AccountDto, AccountSummaryRow, GeneralLedgerRow } from '../../../services/analytics/models';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
const SoCaiPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [tab, setTab] = useState<'summary'|'ledger'>('summary');
  const [accountCode, setAccountCode] = useState('');
  const [accounts, setAccounts] = useState<AccountDto[]>([]);
  const [summary, setSummary] = useState<AccountSummaryRow[]>([]);
  const [ledger, setLedger] = useState<GeneralLedgerRow[]>([]);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  React.useEffect(() => { let c=false; const t=setTimeout(()=>{ analyticsService.getAccounts({ isDetail: true }).then(d=>{if(!c)setAccounts(d);}).catch(()=>{}); },0); return ()=>{c=true;clearTimeout(t);}; }, []);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ const p={ fromDate, toDate, accountCode: accountCode||undefined };
    (tab==='summary'? analyticsService.getAccountSummary(p): (accountCode? analyticsService.getGeneralLedger(p): Promise.resolve([])))
      .then(d=>{ if(!c){ if(tab==='summary') setSummary(d as AccountSummaryRow[]); else setLedger(d as GeneralLedgerRow[]);} })
      .catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));}).finally(()=>{if(!c)setLoading(false);});
  },0); return ()=>{c=true;clearTimeout(t);}; }, [fromDate,toDate,tab,accountCode,dispatch, reloadKey]);
  const rows = tab==='summary'? summary : ledger;
  const refresh = () => setReloadKey(k => k + 1);
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-book-open" /> Sổ cái</h1></div>
        <div className={styles.headerActions}><Button variant="secondary" onClick={()=>exportExcel(tab==='summary'?'/accounting/account-summary/export-excel':'/accounting/general-ledger/export-excel',{fromDate,toDate,accountCode:accountCode||undefined},`SoCai-${fromDate}.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.filtersBar} data-testid={`erp-so-cai-filters`}><DateRangeFilter fromDate={fromDate} toDate={toDate} onChange={(v:DateRangeValue)=>{setFromDate(v.fromDate??'');setToDate(v.toDate??'');}} /><Select value={accountCode} onChange={e=>setAccountCode(e.target.value)} options={[{value:'',label:'Tài khoản'},...accounts.map(a=>({value:a.code,label:`${a.code} — ${a.name}`}))]} size="small" /></div>
      <div className={styles.tabs}><button type="button" className={tab==='summary'?styles.tabActive:styles.tab} onClick={()=>setTab('summary')}>Sổ TH</button><button type="button" className={tab==='ledger'?styles.tabActive:styles.tab} onClick={()=>setTab('ledger')}>Sổ cái</button><ListSearchRefreshButtons testIdPrefix="erp-so-cai" onSearch={handleSearch} onRefresh={refresh} showSearch={false} /></div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:rows.length===0?<div className={styles.empty}><p>Không có dữ liệu</p></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr>{tab==='summary'?<><th>TK</th><th>Tên</th><th className={styles.colRight}>Nợ ĐK</th><th className={styles.colRight}>Có ĐK</th><th className={styles.colRight}>PS Nợ</th><th className={styles.colRight}>PS Có</th><th className={styles.colRight}>Nợ CK</th><th className={styles.colRight}>Có CK</th></>:<><th>Ngày</th><th>Số CT</th><th>Diễn giải</th><th className={styles.colRight}>Nợ</th><th className={styles.colRight}>Có</th><th className={styles.colRight}>Số dư</th></>}</tr></thead><tbody>
        {tab==='summary'? summary.map((r,i)=>(<tr key={i}><td>{r.code}</td><td>{r.name}</td><td className={styles.colRight}>{formatVnd(r.openingDebit)}</td><td className={styles.colRight}>{formatVnd(r.openingCredit)}</td><td className={styles.colRight}>{formatVnd(r.periodDebit)}</td><td className={styles.colRight}>{formatVnd(r.periodCredit)}</td><td className={styles.colRight}>{formatVnd(r.closingDebit)}</td><td className={styles.colRight}>{formatVnd(r.closingCredit)}</td></tr>))
        : ledger.map((r,i)=>(<tr key={i}><td>{formatDate(r.voucherDate)}</td><td>{r.voucherNumber}</td><td>{r.description??'—'}</td><td className={styles.colRight}>{formatVnd(r.debitAmount)}</td><td className={styles.colRight}>{formatVnd(r.creditAmount)}</td><td className={styles.colRight}>{formatVnd(r.balance)}</td></tr>))}
      </tbody></table></div>}</div>
    </div>
  );
};
export default SoCaiPage;
